const IMG_TETIA = "data:image/jpeg;base64,";
const IMG_MAOMAO = "data:image/jpeg;base64,";
const IMG_COCO = "data:image/jpeg;base64,";
const IMG_FRIEREN = "data:image/jpeg;base64,";
document.addEventListener("DOMContentLoaded", function() {
  document.querySelectorAll("[data-isrc]").forEach(function(el) {
    var v = el.getAttribute("data-isrc");
    var map = {IMG_TETIA: IMG_TETIA, IMG_MAOMAO: IMG_MAOMAO, IMG_COCO: IMG_COCO, IMG_FRIEREN: IMG_FRIEREN};
    if (map[v]) el.src = map[v];
  });
});
